import "./Button01.css";

import icon from "../../img/logo/favicon.png";

const Button01 = () => {
  return (
    <div className="Button01">
      <button
        type="button"
        aria-label="Primary action — wire this button when you add routes or sections"
      >
        <div className="Button01-icon">
          <img src={icon} alt="icon" />
        </div>

        <p>Primary action</p>

        <div className="Button01-bg"></div>
      </button>
    </div>
  );
};

export default Button01;
