import "./navbar.css";

import { Link } from "react-router-dom";
import { useState, useEffect } from "react";

import logo from "../../img/logo/favicon.png";
import instagram from "../../img/icons/brand-instagram.svg";
import twitter from "../../img/icons/brand-x.svg";
import telegram from "../../img/icons/brand-telegram.svg";
import email from "../../img/icons/mail.svg";
import { SITE_NAME } from "../../seo/siteConfig";

function Navbar() {
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };

    window.addEventListener("scroll", handleScroll);

    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  return (
    <header className={`navbar ${isScrolled ? "scrolled" : ""}`}>
      <div className="navbar-box">
        <Link
          to="/"
          className="navbar-icon"
          onClick={() => {
            window.scroll(0, 0);
          }}
        >
          <img src={instagram} alt="instagram"></img>
        </Link>

        <Link
          to="/"
          className="navbar-icon"
          onClick={() => {
            window.scroll(0, 0);
          }}
        >
          <img src={twitter} alt="twitter"></img>
        </Link>

        <Link
          to="/"
          className="navbar-icon"
          onClick={() => {
            window.scroll(0, 0);
          }}
        >
          <img src={logo} alt="logo"></img>
        </Link>

        <Link
          to="/"
          className="navbar-icon"
          onClick={() => {
            window.scroll(0, 0);
          }}
        >
          <img src={telegram} alt="telegram"></img>
        </Link>

        <Link
          to="/"
          className="navbar-icon"
          onClick={() => {
            window.scroll(0, 0);
          }}
        >
          <img src={email} alt="email"></img>
        </Link>
      </div>
    </header>
  );
}

export default Navbar;
