/** Production site origin (no trailing slash). Replace when you launch. */
export const SITE_ORIGIN = "https://servednet.com";

export const SITE_NAME = "ServedNet";

export const TITLE_SUFFIX = " | ServedNet";

/**
 * Default Open Graph / Twitter image path. Prefer /og-image.png at 1200×630 when available.
 */
export const DEFAULT_OG_IMAGE_PATH = "/og-image.png";

export const HOME_PAGE_TITLE = `${SITE_NAME} | Home`;

export const HOME_PAGE_DESCRIPTION =
  "Replace this description with a concise summary of your site for search and social previews.";

/** Optional full URL to a privacy policy (in-app route or external). Leave empty to hide the link in the cookie banner. */
export const PRIVACY_POLICY_URL = "";

/**
 * @param {string} text
 * @param {number} max
 * @returns {string}
 */
export function truncateMetaDescription(text, max = 160) {
  if (!text) return "";
  const t = text.trim();
  if (t.length <= max) return t;
  return `${t.slice(0, max - 1).trimEnd()}\u2026`;
}

/**
 * @param {string} path
 * @returns {string}
 */
export function absoluteUrl(path) {
  const p = path.startsWith("/") ? path : `/${path}`;
  return `${SITE_ORIGIN}${p}`;
}
