import React, { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import "./ScrollSequence01.css";

gsap.registerPlugin(ScrollTrigger);

/**
 * Canvas scrubbed sequence from static files under `public/`.
 * Defaults match `public/sequences/bg-logo/ezgif-frame-001.png` … `ezgif-frame-240.png`.
 * Optional `endSelector`: last frame at scroll Y where that element’s top hits the viewport top.
 */
export default function ScrollSequence01({
  frameCount = 192,
  folderPath = "/sequences/bg-logo2/",
  filePrefix = "anim-",
  fileExtension = "png",
  padLength = 3,
  canvasWidth = 1920,
  canvasHeight = 1080,
  endSelector,
}) {
  const canvasRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return undefined;

    const context = canvas.getContext("2d");
    const base =
      folderPath.endsWith("/") || folderPath === ""
        ? folderPath
        : `${folderPath}/`;

    const images = [];
    const scrubState = { frame: 0 };

    for (let i = 0; i < frameCount; i++) {
      const img = new Image();
      const paddedIndex = (i + 1).toString().padStart(padLength, "0");
      img.src = `${base}${filePrefix}${paddedIndex}.${fileExtension}`;
      images.push(img);
    }

    images[0].onload = () => {
      context.drawImage(images[0], 0, 0, canvasWidth, canvasHeight);
    };

    const maxScrollY = () =>
      Math.max(1, document.documentElement.scrollHeight - window.innerHeight);

    const endScrollY = () => {
      const maxY = maxScrollY();
      if (!endSelector) return maxY;
      const el = document.querySelector(endSelector);
      if (!el) return maxY;
      const top = el.getBoundingClientRect().top + window.scrollY;
      return Math.max(1, Math.min(top, maxY));
    };

    const scrollAnimation = gsap.to(scrubState, {
      frame: frameCount - 1,
      snap: "frame",
      ease: "none",
      scrollTrigger: {
        trigger: document.documentElement,
        start: 0,
        end: endScrollY,
        scrub: 0.75,
        pin: false,
      },
      onUpdate: () => {
        context.clearRect(0, 0, canvasWidth, canvasHeight);
        const frame = Math.round(scrubState.frame);
        if (images[frame]) {
          context.drawImage(images[frame], 0, 0, canvasWidth, canvasHeight);
        }
      },
    });

    return () => {
      scrollAnimation.kill();
      ScrollTrigger.getAll().forEach((t) => t.kill());
    };
  }, [
    frameCount,
    folderPath,
    filePrefix,
    fileExtension,
    padLength,
    canvasWidth,
    canvasHeight,
    endSelector,
  ]);

  return (
    <div ref={containerRef} className="ScrollSequence01">
      <canvas
        ref={canvasRef}
        width={canvasWidth}
        height={canvasHeight}
        className="ScrollSequence01-canvas"
      />
    </div>
  );
}
