import { Fragment } from "react";

import { useScrollReveal } from "../../../hooks/useScrollReveal";
import { useScrollProgress } from "../../../hooks/useScrollProgress";
import "./Quote02.css";

const QUOTE_PARTS = [
  {
    accent: true,
    text: "A closed ecosystem ",
  },
  {
    accent: false,
    text: "of the industry's ",
  },
  { accent: true, text: "highest-performing talent." },
];

function buildWords() {
  const out = [];
  for (const part of QUOTE_PARTS) {
    for (const word of part.text.split(/\s+/).filter(Boolean)) {
      out.push({ word, accent: part.accent });
    }
  }
  return out;
}

const QUOTE_WORDS = buildWords();

/** Raw scroll progress (0–1) at which all words are visible; lower = completes earlier. */
const QUOTE_SCROLL_FINISH_AT = 0.3;

function Quote02() {
  const { ref, isVisible } = useScrollReveal();
  const progress = useScrollProgress(ref, QUOTE_SCROLL_FINISH_AT);

  const n = QUOTE_WORDS.length;
  const visibleCount = n === 0 ? 0 : Math.min(n, Math.floor(progress * n));

  return (
    <div ref={ref} className="Quote02 section" id="Quote02">
      <div className="container">
        <div
          className={`Quote02-box section-reveal ${isVisible ? "section--visible" : ""}`}
        >
          <h1>
            {QUOTE_WORDS.map((item, index) => (
              <Fragment key={index}>
                {index > 0 ? " " : null}
                <span
                  className={`Quote02-word ${item.accent ? "Quote02-word--accent" : ""} ${
                    index < visibleCount ? "Quote02-word--visible" : ""
                  }`}
                >
                  {item.word}
                </span>
              </Fragment>
            ))}
          </h1>
        </div>
      </div>
    </div>
  );
}

export default Quote02;
