import { useEffect } from "react";
import { useRive } from "@rive-app/react-webgl2";

import "./RivePlayer01.css";

const RivePlayer = ({
  src,
  stateMachine = "State Machine 1",
  onRiveReady,
  shouldPlay = false,
}) => {
  const { rive, RiveComponent } = useRive({
    src: src,
    autoplay: false,
    stateMachines: stateMachine,
    onRiveReady,
  });

  useEffect(() => {
    if (!rive) return;
    if (shouldPlay) {
      rive.play();
    } else {
      rive.pause();
    }
  }, [rive, shouldPlay]);

  return (
    <div className="RivePlayer01-wrapper">
      <RiveComponent />
    </div>
  );
};

export default RivePlayer;
