import { useState } from "react";

import { STORAGE_KEY } from "../../consent/cookieConsent";
import { PRIVACY_POLICY_URL } from "../../seo/siteConfig";

import "./CookieConsent.css";

function CookieConsent() {
  const [acknowledged, setAcknowledged] = useState(() => {
    try {
      return Boolean(window.localStorage.getItem(STORAGE_KEY));
    } catch {
      return false;
    }
  });

  const accept = () => {
    try {
      window.localStorage.setItem(STORAGE_KEY, "accepted");
    } catch {
      /* ignore */
    }
    setAcknowledged(true);
  };

  if (acknowledged) return null;

  return (
    <div
      className="CookieConsent"
      role="dialog"
      aria-modal="false"
      aria-label="Cookie notice"
    >
      <div className="CookieConsent-inner">
        <p className="CookieConsent-text">
          We use cookies and similar technologies to run this site and remember
          your preferences. By continuing, you agree to our use of these
          technologies.
          {PRIVACY_POLICY_URL ? (
            <>
              {" "}
              Read our{" "}
              <a
                href={PRIVACY_POLICY_URL}
                className="CookieConsent-link"
                target="_blank"
                rel="noopener noreferrer"
              >
                Privacy Policy
              </a>
              .
            </>
          ) : (
            <> Add a privacy policy URL in siteConfig when you publish one.</>
          )}
        </p>
        <button
          type="button"
          className="btn-3 CookieConsent-accept"
          onClick={accept}
        >
          Accept
        </button>
      </div>
    </div>
  );
}

export default CookieConsent;
